\title{Schur Q-Polynomials and Kontsevich-Witten Tau Function}

\author{Xiaobo Liu \thanks{Research was partially supported by NSFC grants 11890662 and 11890660.}, Chenglang Yang}



\date{}

\begin{document}



\maketitle


\begin{abstract}
	Using matrix model, Mironov and Morozov recently gave a formula which represents Kontsevich-Witten tau-function as a linear expansion of Schur Q-polynomials.  In this paper, we will show directly that the Q-polynomial expansion in this formula satisfies the Virasoro constraints, and consequently obtain a proof of this formula without using matrix model. We also give a proof for Alexandrov's conjecture that  Kontsevich-Witten tau-function is a hypergeometric tau-function of the BKP hierarchy after re-scaling.
\end{abstract}

.}


\title{Q-polynomial expansion for Br\'{e}zin-Gross-Witten tau-function}
\author{Xiaobo Liu \thanks{Research was partially supported by NSFC grants 11890662 and 11890660.}, Chenglang Yang}
\date{}

\begin{document}
\maketitle

\begin{abstract}
	In this paper, we prove a conjecture of Alexandrov that the generalized Br\'{e}zin-Gross-Witten tau-functions are hypergeometric
tau functions of BKP hierarchy after re-scaling. In particular, this shows that the original BGW tau-function, which has enumerative geometric interpretations, can be represented as a linear combination of Schur Q-polynomials with simple coefficients.
\end{abstract}

